const d = $json;

const LABELS_INTENCION = {
  inversion: 'Inversión',
  segunda_vivienda: 'Segunda vivienda',
  vivir_permanente: 'Vivir permanente',
  evaluando: 'Evaluando',
  no_definido: 'No definido',
};
const LABELS_USO = {
  inversion: 'Inversión',
  segunda: 'Segunda vivienda',
  vivienda: 'Vivienda principal',
  no_definido: 'No definido',
};
const LABELS_PLAZO = {
  ahora: 'Ahora',
  '1_a_3_meses': '1 a 3 meses',
  '3_a_6_meses': '3 a 6 meses',
  '6_a_12_meses': '6 a 12 meses',
  'mas_de_1_ano': 'Más de 1 año',
  no_definido: 'No definido',
};
const LABELS_FORMA_PAGO = {
  contado: 'Contado',
  credito: 'Crédito',
  mixto: 'Mixto',
  subsidio: 'Subsidio',
  no_definido: 'No definido',
};
const LABELS_DECISOR = {
  solo: 'Solo',
  pareja: 'Con pareja',
  familia: 'Con familia',
  no_definido: 'No definido',
};
const LABELS_MOTIVO = {
  lead_solicito: 'Lead pidio hablar con asesor',
  bot_no_pudo_resolver: 'Bot no pudo resolver duda',
  score_alto_proactivo: 'Score alto, bot ofrecio contacto',
};

const isBrokerRequest = d.broker_request === true || !!d.motivo;
const emoji = isBrokerRequest ? '🔔' : (d.score === 'CALIENTE' ? '🟢' : d.score === 'TIBIO' ? '🟡' : '🔵');
const titulo = isBrokerRequest
  ? 'SOLICITUD DE CONTACTO'
  : (d.score === 'CALIENTE' ? 'NUEVO LEAD CALIENTE' : d.score === 'TIBIO' ? 'NUEVO LEAD TIBIO' : 'NUEVO LEAD FRÍO');

const usoLabel = LABELS_USO[d.uso] || LABELS_INTENCION[d.intencion] || d.uso || d.intencion || '—';
const formaPagoLabel = LABELS_FORMA_PAGO[d.forma_pago] || LABELS_FORMA_PAGO[d.presupuesto] || d.forma_pago || d.presupuesto || '—';
const rango = d.rango_presupuesto && d.rango_presupuesto !== 'no_definido' ? ` (${d.rango_presupuesto})` : '';
const preApr = typeof d.pre_aprobacion === 'boolean' ? (d.pre_aprobacion ? ' · pre-aprobado' : ' · sin preapr') : '';
const scoreLine = d.score_numeric !== undefined && d.score_numeric !== null
  ? `${d.score} (${d.score_numeric}/100)`
  : (d.score || '—');

const texto = [
  `${emoji} ${titulo} — Mirador Villarrica`,
  `⭐ Score: ${scoreLine}`,
  '',
  `👤 ${d.nombre || 'Sin nombre'}`,
  d.whatsapp ? `📱 ${d.whatsapp}` : null,
  d.email ? `📧 ${d.email}` : null,
  '',
  `🎯 Uso: ${usoLabel}`,
  `📅 Plazo: ${LABELS_PLAZO[d.plazo] || d.plazo || '—'}`,
  `💰 Pago: ${formaPagoLabel}${rango}${preApr}`,
  d.decisor ? `👥 Decisor: ${LABELS_DECISOR[d.decisor] || d.decisor}` : null,
  '',
  isBrokerRequest && d.motivo ? `📌 Motivo: ${LABELS_MOTIVO[d.motivo] || d.motivo}` : null,
  isBrokerRequest && d.contexto ? `💬 Contexto: ${d.contexto}` : null,
  d.resumen ? `📝 ${d.resumen}` : null,
  '',
  `🔗 Sesión: ${d.session_id || '-'}`,
].filter(Boolean).join('\n');

// Número destino: Hugo (desarrollo). Cambiar a 56940329987 (Diego) en go-live.
return [{ json: {
  text: texto,
  number: '56992533044',
  lead_id: d.lead_id,
  session_id: d.session_id,
  score: d.score || 'FRIO',
  score_numeric: typeof d.score_numeric === 'number' ? d.score_numeric : null,
  // Regla: nunca saltar si es solicitud expresa de broker; si no, mantener skip-FRIO legacy.
  skip_send: isBrokerRequest ? false : (d.score === 'FRIO'),
} }];
